1	"use client";
2	
3	import { useMemo, useState, useTransition } from "react";
4	import Link from "next/link";
5	import { useRouter, usePathname, useSearchParams } from "next/navigation";
6	import { Layers, FileText, Image, Code } from "lucide-react";
7	import { ArtifactCard } from "./ArtifactCard";
8	import type { Artifact, ArtifactType } from "@/types";
9	
10	/*
11	 * TAG FILTERING — CLIENT-SIDE (current phase)
12	 *
13	 * Why this is acceptable now: the gallery is a bounded, single-tenant dataset
14	 * (tens to low hundreds of artifacts). Fetching all type-filtered records and
15	 * filtering tags in the browser is imperceptible at this scale and avoids a
16	 * round-trip per keystroke.
17	 *
18	 * Production-scale path: replace the client-side filter below with a debounced
19	 * server-side search. Options in order of complexity:
20	 *   1. Postgres GIN index on the `tags` array + pg_trgm for case-insensitive
21	 *      prefix matching (`WHERE EXISTS (SELECT 1 FROM unnest(tags) t WHERE t ILIKE $1)`).
22	 *      Fits a single-table model with moderate tag cardinality.
23	 *   2. Normalized `artifact_tags(artifact_id, tag)` table with a btree index on
24	 *      lower(tag). Enables efficient exact + prefix queries and tag analytics.
25	 *   3. Postgres full-text search or trigram index on a `tags_tsv` generated column
26	 *      if tags are long phrases rather than short slugs.
27	 *   4. Dedicated search service (Typesense, Meilisearch, or Elasticsearch) if the
28	 *      catalog grows past ~10k artifacts or requires faceting, ranking, and typo
29	 *      tolerance.
30	 *
31	 * To migrate: replace `useLocalTagFilter` with a debounced `useSearchParams` push
32	 * and move the filtering back into `listArtifacts` (or a new `searchArtifacts`
33	 * service function). The component's prop interface and render tree stay the same.
34	 */
35	
36	const TYPES: { value: ArtifactType | ""; label: string; icon: typeof Layers }[] = [
37	  { value: "",      label: "All",   icon: Layers },
38	  { value: "pdf",   label: "PDF",   icon: FileText },
39	  { value: "image", label: "Image", icon: Image },
40	  { value: "html",  label: "HTML",  icon: Code },
41	];
42	
43	interface Props {
44	  artifacts: Artifact[];
45	}
46	
47	export function GalleryFilter({ artifacts }: Props) {
48	  const router = useRouter();
49	  const pathname = usePathname();
50	  const searchParams = useSearchParams();
51	  const [isPending, startTransition] = useTransition();
52	
53	  const currentType = searchParams.get("type") ?? "";
54	
55	  // Local state: decoupled from URL so typing never triggers router.push.
56	  // Initialised once from the URL so a bookmarked ?tag= still pre-fills the input.
57	  const [tagInput, setTagInput] = useState(() => searchParams.get("tag") ?? "");
58	
59	  // Client-side partial, case-insensitive tag filter.
60	  // Runs synchronously in the browser — no network round-trip per keystroke.
61	  const filteredArtifacts = useMemo(() => {
62	    const q = tagInput.trim().toLowerCase();
63	    if (!q) return artifacts;
64	    return artifacts.filter((a) =>
65	      a.tags.some((t) => t.toLowerCase().startsWith(q))
66	    );
67	  }, [artifacts, tagInput]);
68	
69	  const hasFilter = currentType || tagInput;
70	
71	  // Type filter: discrete click → URL param → server re-fetch. Correct path for
72	  // access-controlled, visibility-filtered, server-authoritative data.
73	  function updateType(value: string) {
74	    startTransition(() => {
75	      const params = new URLSearchParams(searchParams.toString());
76	      if (value) params.set("type", value);
77	      else params.delete("type");
78	      // Drop tag from URL — it lives in local state; no need to round-trip it.
79	      params.delete("tag");
80	      router.push(`${pathname}?${params.toString()}`);
81	    });
82	  }
83	
84	  function clearAll() {
85	    setTagInput("");
86	    router.push(pathname);
87	  }
88	
89	  return (
90	    <>
91	      {/* Filter row */}
