"use client";

import type { ArtifactType } from "@/types";

interface Props {
  type: ArtifactType;
  signedUrl: string;
  title: string;
}

export function ArtifactPreview({ type, signedUrl, title }: Props) {
  if (type === "image") {
    return (
      <div className="flex items-center justify-center rounded-xl border border-border bg-card overflow-hidden min-h-48">
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={signedUrl}
          alt={title}
          className="max-h-[600px] w-full object-contain"
        />
      </div>
    );
  }

  if (type === "pdf") {
    return (
      <div className="rounded-xl border border-border overflow-hidden" style={{ height: 700 }}>
        <iframe
          src={signedUrl}
          title={title}
          className="h-full w-full"
          loading="lazy"
        />
      </div>
    );
  }

  return (
    <div className="rounded-xl border border-border overflow-hidden" style={{ height: 600 }}>
      <iframe
        src={signedUrl}
        title={title}
        className="h-full w-full"
        sandbox="allow-scripts allow-forms"
        loading="lazy"
      />
    </div>
  );
}

import { Suspense } from "react";
import { listArtifacts } from "@/lib/services/artifacts";
import { GalleryFilter } from "@/components/GalleryFilter";
import { Header } from "@/components/Header";
import type { ArtifactType } from "@/types";

// Bounded dataset assumption: fetch enough records for client-side tag filtering.
// Safe while the public artifact count stays well below this number.
// When approaching this limit, replace client-side tag filtering with debounced
// server-side search (see GalleryFilter.tsx for the production migration path).
const GALLERY_CLIENT_FILTER_LIMIT = 500;

interface Props {
  searchParams: Promise<{ type?: string }>;
}

export default async function GalleryPage({ searchParams }: Props) {
  const { type } = await searchParams;

  // Type filter is server-authoritative: visibility, access control, and
  // pagination stay here. Tag search is handled client-side — see GalleryFilter.
  const result = await listArtifacts({
    visibility: "public",
    type: (type as ArtifactType) || undefined,
    limit: GALLERY_CLIENT_FILTER_LIMIT,
  });

  if (!result.ok) {
    return (
      <div className="min-h-screen bg-background">
        <Header />
        <main className="mx-auto max-w-6xl px-6 py-8">
          <div className="rounded-xl border border-destructive/30 bg-destructive/10 p-6 text-sm text-destructive">
            Failed to load artifacts: {result.message}
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <Header />

      <main className="mx-auto max-w-6xl px-6 py-8">
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight text-foreground mb-2">Gallery</h1>
          <p className="text-muted-foreground">Browse and manage your generated artifacts</p>
        </div>

        <Suspense fallback={null}>
          <GalleryFilter artifacts={result.data} />
        </Suspense>
      </main>
    </div>
  );
}

"use client";

import { useState } from "react";
import type { FeedbackSummary as FeedbackSummaryType } from "@/types";

interface Props {
  artifactId: string;
  initialSummary: FeedbackSummaryType | null;
  feedbackCount: number;
}

export function FeedbackSummary({ artifactId, initialSummary, feedbackCount }: Props) {
  const [summary, setSummary] = useState(initialSummary);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const isStale = summary !== null && summary.feedback_count !== feedbackCount;
  const hasFeedback = feedbackCount > 0;

  async function generate(forceRefresh = false) {
    setLoading(true);
    setError("");
    try {
      const res = await fetch(`/api/artifacts/${artifactId}/summarize`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ force_refresh: forceRefresh }),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error ?? "Failed to generate summary");
      }
      const data = await res.json();
      setSummary(data.summary);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setLoading(false);
    }
  }

  if (!hasFeedback) return null;

  return (
    <div className="rounded-xl border border-border bg-card p-5 space-y-4">
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex items-center gap-2">
          <h3 className="font-semibold text-foreground">Feedback summary</h3>
          {isStale && (
            <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
              Stale
            </span>
          )}
        </div>
        {!summary ? (
          <button
            onClick={() => generate(false)}
            disabled={loading}
            className="inline-flex items-center gap-1.5 rounded-lg bg-primary px-3 py-1.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-50"
          >
            {loading ? "Generating…" : "Summarize feedback"}
          </button>
        ) : isStale ? (
          <button
            onClick={() => generate(true)}
            disabled={loading}
            className="inline-flex items-center gap-1.5 rounded-lg border border-border bg-card px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-secondary disabled:opacity-50"
          >
            {loading ? "Regenerating…" : "Regenerate"}
          </button>
        ) : null}
      </div>

      {error && <p className="text-sm text-red-500">{error}</p>}

      {loading && !summary && (
        <div className="space-y-2 animate-pulse">
          <div className="h-4 bg-secondary rounded w-3/4" />
          <div className="h-4 bg-secondary rounded w-1/2" />
        </div>
      )}

      {summary && (
        <div className="space-y-4">
          <div className="rounded-lg bg-secondary px-4 py-3">
            <p className="text-sm text-foreground leading-relaxed">
              {summary.summary.overall_assessment}
            </p>
          </div>

          <div className="grid gap-3 sm:grid-cols-2">
            {summary.summary.approval_count > 0 && (
              <SummarySection
                title="Approvals"
                color="green"
                items={[`${summary.summary.approval_count} reviewer${summary.summary.approval_count === 1 ? "" : "s"} approved this artifact`]}
                single
              />
            )}
            {summary.summary.open_issues.length > 0 && (
              <SummarySection title="Open issues" color="red" items={summary.summary.open_issues} />
            )}
            {summary.summary.suggestions.length > 0 && (
              <SummarySection title="Suggestions" color="blue" items={summary.summary.suggestions} />
            )}
            {summary.summary.questions.length > 0 && (
              <SummarySection title="Questions" color="amber" items={summary.summary.questions} />
            )}
          </div>

          <p className="text-xs text-muted-foreground">
            Generated from {summary.feedback_count} feedback item{summary.feedback_count === 1 ? "" : "s"}
            {summary.model ? ` · ${summary.model}` : ""}
          </p>
        </div>
      )}
    </div>
  );
}

function SummarySection({
  title,
  color,
  items,
  single = false,
}: {
  title: string;
  color: "green" | "red" | "blue" | "amber";
  items: string[];
  single?: boolean;
}) {
  const colors = {
    green: "text-green-700 bg-green-50 border-green-200",
    red:   "text-red-700   bg-red-50   border-red-200",
    blue:  "text-blue-700  bg-blue-50  border-blue-200",
    amber: "text-amber-700 bg-amber-50 border-amber-200",
  };
  const titleColors = {
    green: "text-green-800",
    red:   "text-red-800",
    blue:  "text-blue-800",
    amber: "text-amber-800",
  };

  return (
    <div className={`rounded-lg border px-3 py-2.5 ${colors[color]}`}>
      <p className={`text-xs font-semibold uppercase tracking-wide mb-1.5 ${titleColors[color]}`}>
        {title}
      </p>
      {single ? (
        <p className="text-sm">{items[0]}</p>
      ) : (
        <ul className="space-y-1">
          {items.map((item, i) => (
            <li key={i} className="text-sm flex gap-1.5">
              <span className="shrink-0 mt-0.5">·</span>
              <span>{item}</span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

