          type: "text" as const,
          text: `Found ${data.length} artifact${data.length === 1 ? "" : "s"}.\n\n${lines.join("\n\n")}\n\n→ Use get_artifact with any ID above for full details and feedback.`,
        }],
      };
    }
  );

  server.tool(
    "get_artifact",
