        .describe("Type of feedback"),
      comment: z.string().min(1).describe("Your feedback comment"),
    },
    async ({ artifact_id, reviewer_name, reviewer_role, feedback_type, comment }) => {
      const data = (await client.post("/api/mcp/feedback", {
        artifact_id,
        reviewer_name,
        reviewer_role,
        feedback_type,
        comment,
