            </span>
          )}
        </div>
      </div>

      {/* Description */}
      {artifact.description && (
        <p className="text-muted-foreground text-sm leading-relaxed line-clamp-2 mb-4">
          {artifact.description}
        </p>
      )}

      {/* Tags */}
      {artifact.tags.length > 0 && (
        <div className="flex flex-wrap gap-1.5 mb-4">
